Here's a complete example:

**XAML (ItemsPage.xaml)**
```xml
<ContentPage xmlns="http://schemas.microsoft.com/dotnet/2021/maui"
             xmlns:x="http://schemas.microsoft.com/winfx/2009/xaml"
             x:Class="MyApp.ItemsPage"
             Title="Items">

    <CollectionView ItemsSource="{Binding Items}"
                    SelectionMode="Single"
                    SelectedItem="{Binding SelectedItem}"
                    IsRefreshing="{Binding IsRefreshing}"
                    RemainingItemsThreshold="0">

        <!-- Pull-to-refresh via RefreshView wrapper -->
        <CollectionView.Parent>
            <!-- see note below -->
        </CollectionView.Parent>

        <CollectionView.ItemTemplate>
            <DataTemplate>
                <VerticalStackLayout Padding="10">
                    <Label Text="{Binding Name}" FontSize="18" />
                    <Label Text="{Binding Description}" FontSize="14"
                           TextColor="Gray" />
                </VerticalStackLayout>
            </DataTemplate>
        </CollectionView.ItemTemplate>
    </CollectionView>

</ContentPage>
```

Since `CollectionView` doesn't have a built-in refresh, wrap it in a `RefreshView`:

```xml
<RefreshView Command="{Binding RefreshCommand}"
             IsRefreshing="{Binding IsRefreshing}">

    <CollectionView ItemsSource="{Binding Items}"
                    SelectionMode="Single"
                    SelectedItem="{Binding SelectedItem}">
        <CollectionView.ItemTemplate>
            <DataTemplate>
                <VerticalStackLayout Padding="10">
                    <Label Text="{Binding Name}" FontSize="18" />
                    <Label Text="{Binding Description}" FontSize="14"
                           TextColor="Gray" />
                </VerticalStackLayout>
            </DataTemplate>
        </CollectionView.ItemTemplate>
    </CollectionView>

</RefreshView>
```

**ViewModel (ItemsViewModel.cs)**
```csharp
public partial class ItemsViewModel : ObservableObject
{
    private readonly IApiService _api;
    private readonly INavigationService _nav;

    public ItemsViewModel(IApiService api, INavigationService nav)
    {
        _api = api;
        _nav = nav;
    }

    [ObservableProperty]
    private ObservableCollection<Item> _items = new();

    [ObservableProperty]
    private bool _isRefreshing;

    [ObservableProperty]
    private Item? _selectedItem;

    // Fires automatically when SelectedItem changes (CommunityToolkit naming convention)
    partial void OnSelectedItemChanged(Item? value)
    {
        if (value is null) return;

        // Navigate, then clear selection so the user can re-select the same item
        _nav.NavigateAsync(nameof(DetailPage), new Dictionary<string, object>
        {
            { "Item", value }
        });

        SelectedItem = null;
    }

    [RelayCommand]
    private async Task RefreshAsync()
    {
        try
        {
            var data = await _api.GetItemsAsync();
            Items = new ObservableCollection<Item>(data);
        }
        finally
        {
            IsRefreshing = false; // stops the spinner
        }
    }
}
```

**Key bindings explained:**

| Binding | Purpose |
|---|---|
| `ItemsSource="{Binding Items}"` | Drives the list from an `ObservableCollection` |
| `SelectedItem="{Binding SelectedItem}"` | Two-way by default; triggers `OnSelectedItemChanged` |
| `SelectionMode="Single"` | Only one item selectable at a time |
| `Command="{Binding RefreshCommand}"` | `RefreshView` calls the `[RelayCommand]`-generated command |
| `IsRefreshing="{Binding IsRefreshing}"` | Controls the refresh spinner; set `false` when done |

**Important details:**
- Set `SelectedItem = null` after navigating so the same row can be tapped again.
- Set `IsRefreshing = false` in a `finally` block so the spinner always stops, even on error.
- Uses **CommunityToolkit.Mvvm** source generators (`[ObservableProperty]`, `[RelayCommand]`).
